import React, { useState, useMemo } from 'react';
import { FiSearch, FiBook, FiAward, FiArrowRight, FiStar } from 'react-icons/fi';

// Mock Data
const MOCK_SKILLS = [
    { id: 1, name: "Machine Learning & AI", platforms: ["Coursera", "edX", "Udacity"], category: "Trending", description: "Master the algorithms that power modern AI." },
    { id: 2, "name": "React.js & Next.js", "platforms": ["Udemy", "Pluralsight"], "category": "Web Dev", description: "Build scalable, high-performance web applications." },
    { id: 3, "name": "Cloud Architecture (AWS)", "platforms": ["A Cloud Guru", "Coursera"], "category": "Cloud", description: "Design and deploy scalable cloud solutions." },
    { id: 4, "name": "UI/UX Design", "platforms": ["Google", "IDF"], "category": "Design", description: "Create user-centric and beautiful interfaces." },
    { id: 5, "name": "Cybersecurity Fundamentals", "platforms": ["CompTIA", "edX"], "category": "Security", description: "Protect systems and data from cyber threats." },
    { id: 6, "name": "Data Engineering", "platforms": ["DataCamp", "Coursera"], "category": "Data", description: "Build robust pipelines for big data processing." },
    { id: 7, "name": "Prompt Engineering", "platforms": ["OpenAI", "Udemy"], "category": "Trending", description: "Optimize interactions with Large Language Models." },
    { id: 8, "name": "Blockchain Development", "platforms": ["Ethereum org", "Coursera"], "category": "Web3", description: "Develop decentralized applications and smart contracts." },
];

const SkillsPage: React.FC = () => {
    const [searchQuery, setSearchQuery] = useState('');

    const filteredSkills = useMemo(() => {
        if (!searchQuery.trim()) {
            return MOCK_SKILLS;
        }
        const lowerQuery = searchQuery.toLowerCase();
        return MOCK_SKILLS.filter(skill => 
            skill.name.toLowerCase().includes(lowerQuery) || 
            skill.category.toLowerCase().includes(lowerQuery) ||
            skill.description.toLowerCase().includes(lowerQuery)
        );
    }, [searchQuery]);

    return (
        <div className="min-h-screen bg-gray-50 pb-12 font-sans">
            {/* Header section */}
            <header className="bg-white border-b border-gray-200 sticky top-0 z-10 shadow-sm">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
                    <div className="flex items-center gap-3">
                        <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-2.5 rounded-xl shadow-md">
                            <FiBook className="text-white" size={24} />
                        </div>
                        <h1 className="text-2xl font-extrabold text-gray-900 tracking-tight">
                            Suggested Skills
                        </h1>
                    </div>
                </div>
            </header>

            <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-10">
                {/* Hero / Search Section */}
                <div className="relative rounded-3xl overflow-hidden shadow-2xl bg-gray-900">
                    <div className="absolute inset-0 bg-gradient-to-br from-blue-900 via-indigo-900 to-purple-900 opacity-90"></div>

                    {/* Decorative elements */}
                    <div className="absolute top-0 right-0 -mt-20 -mr-20 w-80 h-80 bg-blue-500 rounded-full blur-3xl opacity-20 animate-pulse"></div>
                    <div className="absolute bottom-0 left-0 -mb-20 -ml-20 w-72 h-72 bg-purple-500 rounded-full blur-3xl opacity-20 animate-pulse" style={{ animationDelay: '1s' }}></div>

                    <div className="relative p-10 md:p-16 text-center z-10">
                        <h2 className="text-4xl md:text-5xl font-extrabold text-white mb-6 tracking-tight drop-shadow-md">
                            What will you master next?
                        </h2>
                        <p className="text-xl text-blue-100 mb-10 max-w-2xl mx-auto font-light">
                            Discover trending skills and find the best platforms to accelerate your career growth.
                        </p>

                        <div className="max-w-3xl mx-auto relative group">
                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                <FiSearch className="h-6 w-6 text-gray-400 group-focus-within:text-blue-500 transition-colors" />
                            </div>
                            <input
                                type="text"
                                className="block w-full pl-12 pr-4 py-5 rounded-2xl text-lg text-gray-900 placeholder-gray-400 bg-white border-0 shadow-inner focus:ring-4 focus:ring-blue-500 focus:ring-opacity-50 transition-all duration-300"
                                placeholder="Search for skills, roles, or topics..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>
                    </div>
                </div>

                {/* Content Section */}
                <div>
                    <div className="flex items-center justify-between mb-8">
                        <h3 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                            {searchQuery ? (
                                <>Search Results <span className="text-gray-500 text-lg font-normal">({filteredSkills.length})</span></>
                            ) : (
                                <><FiStar className="text-yellow-500 fill-current" /> Trending Now</>
                            )}
                        </h3>
                    </div>

                    {filteredSkills.length > 0 ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                            {filteredSkills.map((skill) => (
                                <div 
                                    key={skill.id} 
                                    className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-xl hover:-translate-y-1 transition-all duration-300 flex flex-col h-full group"
                                >
                                    <div className="flex justify-between items-start mb-4">
                                        <div className="bg-blue-50 text-blue-700 text-xs font-bold px-3 py-1 rounded-full uppercase tracking-wider">
                                            {skill.category}
                                        </div>
                                        <div className="w-10 h-10 rounded-full bg-gray-50 flex items-center justify-center text-gray-400 group-hover:bg-blue-600 group-hover:text-white transition-colors duration-300">
                                            <FiAward size={20} />
                                        </div>
                                    </div>

                                    <h4 className="text-xl font-bold text-gray-900 mb-2 leading-tight">
                                        {skill.name}
                                    </h4>

                                    <p className="text-gray-500 text-sm mb-6 flex-grow">
                                        {skill.description}
                                    </p>

                                    <div className="space-y-4 mt-auto">
                                        <div className="flex flex-wrap gap-2">
                                            {skill.platforms.map((platform, idx) => (
                                                <span 
                                                    key={idx} 
                                                    className="inline-flex items-center px-2.5 py-1 rounded-md text-xs font-medium bg-gray-100 text-gray-800"
                                                >
                                                    {platform}
                                                </span>
                                            ))}
                                        </div>

                                        <button className="w-full flex items-center justify-center gap-2 bg-gray-900 hover:bg-blue-600 text-white py-3 rounded-xl font-semibold transition-colors duration-300 group/btn">
                                            <span>View Skill</span>
                                            <FiArrowRight className="transform group-hover/btn:translate-x-1 transition-transform" />
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="text-center py-20 bg-white rounded-3xl shadow-sm border border-gray-100">
                            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-gray-100 mb-4">
                                <FiSearch className="h-8 w-8 text-gray-400" />
                            </div>
                            <h3 className="text-xl font-bold text-gray-900 mb-2">No skills found</h3>
                            <p className="text-gray-500 max-w-md mx-auto">
                                We couldn't find any skills matching "{searchQuery}". Try searching for something else or explore our trending skills.
                            </p>
                            <button 
                                onClick={() => setSearchQuery('')}
                                className="mt-6 text-blue-600 font-semibold hover:text-blue-800 transition-colors"
                            >
                                Clear search
                            </button>
                        </div>
                    )}
                </div>
            </main>
        </div>
    );
};

export default SkillsPage;
